import{_ as s,o as a,c as o,a2 as t}from"./chunks/framework.B72_uj9U.js";const h=JSON.parse('{"title":"ForgeCode — Tool System & Tool Corrections","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/forgecode/tool-system.md","filePath":"research/agents/forgecode/tool-system.md"}'),n={name:"research/agents/forgecode/tool-system.md"};function l(r,e,i,c,p,d){return a(),o("div",null,[...e[0]||(e[0]=[t(`<h1 id="forgecode-—-tool-system-tool-corrections" tabindex="-1">ForgeCode — Tool System &amp; Tool Corrections <a class="header-anchor" href="#forgecode-—-tool-system-tool-corrections" aria-label="Permalink to &quot;ForgeCode — Tool System &amp; Tool Corrections&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>ForgeCode&#39;s tool system is standard for a terminal coding agent — file operations, shell execution, search — but what distinguishes it is the <strong>tool-call correction layer</strong> that sits between the model&#39;s tool-call output and actual execution. This layer was the single highest-impact engineering decision in reaching #1 on TermBench 2.0.</p><h2 id="available-tools" tabindex="-1">Available Tools <a class="header-anchor" href="#available-tools" aria-label="Permalink to &quot;Available Tools&quot;">​</a></h2><p>Based on the open-source codebase and documentation, ForgeCode provides these core tools:</p><h3 id="file-operations" tabindex="-1">File Operations <a class="header-anchor" href="#file-operations" aria-label="Permalink to &quot;File Operations&quot;">​</a></h3><ul><li><strong><code>read_file</code></strong> / <strong><code>read_image</code></strong>: Read file contents (text files truncated at <code>FORGE_MAX_LINE_LENGTH</code>, default 2000 chars/line)</li><li><strong><code>edit</code></strong> (<code>old_string</code> / <code>new_string</code>): Structured file editing with find-and-replace semantics</li><li><strong><code>write_file</code></strong>: Create or overwrite files</li><li><strong><code>search</code></strong>: Code search with configurable result size (<code>FORGE_MAX_SEARCH_RESULT_BYTES</code>)</li></ul><h3 id="shell-execution" tabindex="-1">Shell Execution <a class="header-anchor" href="#shell-execution" aria-label="Permalink to &quot;Shell Execution&quot;">​</a></h3><ul><li><strong><code>shell</code></strong>: Execute arbitrary shell commands with the user&#39;s permissions</li><li>Runs in the user&#39;s native ZSH environment (aliases, functions, PATH all work)</li><li>Timeout controlled by <code>FORGE_TOOL_TIMEOUT</code> (default 300 seconds)</li><li>Output truncated at <code>FORGE_STDOUT_MAX_LINE_LENGTH</code> (default 2000 chars/line)</li></ul><h3 id="semantic-search" tabindex="-1">Semantic Search <a class="header-anchor" href="#semantic-search" aria-label="Permalink to &quot;Semantic Search&quot;">​</a></h3><ul><li><strong><code>sem_search</code></strong>: Semantic code search over an indexed codebase (requires ForgeCode Services + <code>:sync</code>)</li><li>Uses vector search with configurable limits (<code>FORGE_SEM_SEARCH_LIMIT</code>, <code>FORGE_SEM_SEARCH_TOP_K</code>)</li></ul><h3 id="task-management" tabindex="-1">Task Management <a class="header-anchor" href="#task-management" aria-label="Permalink to &quot;Task Management&quot;">​</a></h3><ul><li><strong><code>todo_write</code></strong>: Create, update, and mark task items — enforced as mandatory for multi-step tasks by ForgeCode Services</li></ul><h2 id="tool-call-failure-taxonomy" tabindex="-1">Tool-Call Failure Taxonomy <a class="header-anchor" href="#tool-call-failure-taxonomy" aria-label="Permalink to &quot;Tool-Call Failure Taxonomy&quot;">​</a></h2><p>ForgeCode&#39;s blog posts document three distinct failure classes, discovered through TermBench micro-evaluations:</p><h3 id="_1-wrong-tool-selected" tabindex="-1">1. Wrong Tool Selected <a class="header-anchor" href="#_1-wrong-tool-selected" aria-label="Permalink to &quot;1. Wrong Tool Selected&quot;">​</a></h3><p>The model uses <code>shell</code> to apply a code edit instead of the structured <code>edit</code> tool. This produces working results but bypasses the correction layer&#39;s validation.</p><h3 id="_2-correct-tool-wrong-arguments" tabindex="-1">2. Correct Tool, Wrong Arguments <a class="header-anchor" href="#_2-correct-tool-wrong-arguments" aria-label="Permalink to &quot;2. Correct Tool, Wrong Arguments&quot;">​</a></h3><p>The model calls the right tool but with incorrect argument names or shapes. Field names are close but don&#39;t match the schema exactly.</p><h3 id="_3-correct-tool-correct-arguments-wrong-sequencing" tabindex="-1">3. Correct Tool, Correct Arguments, Wrong Sequencing <a class="header-anchor" href="#_3-correct-tool-correct-arguments-wrong-sequencing" aria-label="Permalink to &quot;3. Correct Tool, Correct Arguments, Wrong Sequencing&quot;">​</a></h3><p>The tool is called before its preconditions are met (e.g., editing a file before reading it to understand the current state).</p><p><strong>Key insight</strong>: These three classes are invisible in aggregate pass-rate metrics. ForgeCode built <strong>per-tool, per-model micro-evaluations</strong> that isolate each failure class individually.</p><h2 id="the-tool-call-correction-layer" tabindex="-1">The Tool-Call Correction Layer <a class="header-anchor" href="#the-tool-call-correction-layer" aria-label="Permalink to &quot;The Tool-Call Correction Layer&quot;">​</a></h2><p>ForgeCode Services provides a runtime correction layer that intercepts every tool call before dispatch. This is not prompt engineering — it&#39;s programmatic interception and repair.</p><h3 id="what-it-does" tabindex="-1">What It Does <a class="header-anchor" href="#what-it-does" aria-label="Permalink to &quot;What It Does&quot;">​</a></h3><ol><li><strong>Argument validation</strong>: Checks that all required fields are present and correctly typed</li><li><strong>Pattern matching</strong>: Catches common error patterns (misnamed fields, wrong nesting levels)</li><li><strong>Auto-correction</strong>: Repairs fixable errors rather than failing silently</li><li><strong>Dispatch gating</strong>: Only valid calls are forwarded to actual execution</li></ol><h3 id="why-it-exists" tabindex="-1">Why It Exists <a class="header-anchor" href="#why-it-exists" aria-label="Permalink to &quot;Why It Exists&quot;">​</a></h3><p>Models have strong priors from training about what tool calls should look like. When your tool&#39;s schema conflicts with those priors (unusual field names, deep nesting, unfamiliar argument patterns), error rates climb — not because the model can&#39;t understand the description, but because it <strong>pattern-matches against training data first</strong>.</p><h2 id="schema-engineering-for-reliability" tabindex="-1">Schema Engineering for Reliability <a class="header-anchor" href="#schema-engineering-for-reliability" aria-label="Permalink to &quot;Schema Engineering for Reliability&quot;">​</a></h2><p>The TermBench blog posts reveal specific schema engineering insights that dramatically improved tool-call reliability:</p><h3 id="field-ordering-matters" tabindex="-1">Field Ordering Matters <a class="header-anchor" href="#field-ordering-matters" aria-label="Permalink to &quot;Field Ordering Matters&quot;">​</a></h3><p>Moving <code>required</code> before <code>properties</code> in JSON schemas reduced malformed calls measurably with GPT 5.4:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// BEFORE (less reliable) — required after properties</span></span>
<span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;object&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">properties</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">title</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;string&quot;</span><span style="color:#9399B2;"> },</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">status</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;string&quot;</span><span style="color:#9399B2;"> }</span><span style="color:#9399B2;"> },</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">required</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;title&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;status&quot;</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// AFTER (more reliable) — required before properties</span></span>
<span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;object&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">required</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;title&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;status&quot;</span><span style="color:#9399B2;">],</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">properties</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">title</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;string&quot;</span><span style="color:#9399B2;"> },</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">status</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;string&quot;</span><span style="color:#9399B2;"> }</span><span style="color:#9399B2;"> }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p><strong>Why</strong>: When GPT 5.4 emits arguments deep in a long trajectory, it anchors on what it sees first. Putting <code>required</code> early tells the model which fields matter before it starts generating the <code>properties</code> block.</p><h3 id="flat-schemas-over-nested" tabindex="-1">Flat Schemas Over Nested <a class="header-anchor" href="#flat-schemas-over-nested" aria-label="Permalink to &quot;Flat Schemas Over Nested&quot;">​</a></h3><p>Nested schemas create structural confusion — models mix up which <code>required</code> array belongs to which object:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// NESTED (more error-prone) — two required arrays, two object layers</span></span>
<span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;object&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">required</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;task&quot;</span><span style="color:#9399B2;">],</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">properties</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">    &quot;</span><span style="color:#89B4FA;">task</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;object&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">required</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;title&quot;</span><span style="color:#9399B2;">],</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">properties</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">title</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;string&quot;</span><span style="color:#9399B2;"> }</span><span style="color:#9399B2;"> }</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">  }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// FLAT (more reliable) — one required array, one object layer</span></span>
<span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;object&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">required</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;task_title&quot;</span><span style="color:#9399B2;">],</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">properties</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">task_title</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;string&quot;</span><span style="color:#9399B2;"> }</span><span style="color:#9399B2;"> }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p><strong>Trade-off</strong>: You lose semantic grouping but gain reliability. ForgeCode chose reliability.</p><h3 id="training-data-aligned-naming" tabindex="-1">Training-Data-Aligned Naming <a class="header-anchor" href="#training-data-aligned-naming" aria-label="Permalink to &quot;Training-Data-Aligned Naming&quot;">​</a></h3><p>Renaming tool arguments to match common training data patterns reduced error rates:</p><ul><li>Generic internal names → <code>old_string</code> / <code>new_string</code> (for edit tools)</li><li>These names appear frequently in training data for file-editing operations</li><li>The model pattern-matches against its training priors, so alignment helps</li></ul><h3 id="explicit-truncation-signals" tabindex="-1">Explicit Truncation Signals <a class="header-anchor" href="#explicit-truncation-signals" aria-label="Permalink to &quot;Explicit Truncation Signals&quot;">​</a></h3><p>When ForgeCode truncates large files (typically at 2000 lines), different models handle the truncation differently:</p><ul><li><strong>Opus 4.6</strong>: Reads <code>total_lines</code> metadata and infers more content exists</li><li><strong>GPT 5.4</strong>: Often proceeds as if it saw the whole file</li></ul><p><strong>Fix</strong>: Add a plain-text reminder directly in the tool result body:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>[NOTE: Output truncated. Showing lines 1-2000 of 5847 total. Use offset to read more.]</span></span></code></pre></div><p>This made truncation handling reliable across models.</p><h2 id="model-specific-tool-behavior" tabindex="-1">Model-Specific Tool Behavior <a class="header-anchor" href="#model-specific-tool-behavior" aria-label="Permalink to &quot;Model-Specific Tool Behavior&quot;">​</a></h2><p>A key finding from the TermBench work: <strong>different models need different tool handling</strong>. ForgeCode&#39;s correction layer applies model-specific adaptations:</p><table tabindex="0"><thead><tr><th>Behavior</th><th>Opus 4.6</th><th>GPT 5.4</th></tr></thead><tbody><tr><td>Schema tolerance</td><td>Handles messy schemas</td><td>Needs clean field ordering</td></tr><tr><td>Nesting</td><td>Handles nested schemas</td><td>Needs flat schemas</td></tr><tr><td>Truncation inference</td><td>Reads metadata</td><td>Needs explicit text reminders</td></tr><tr><td>Verification</td><td>Naturally does extra passes</td><td>Needs enforced verification</td></tr><tr><td>Overall</td><td>More forgiving</td><td>Same score with more runtime support</td></tr></tbody></table><p>This is not a capability gap — it&#39;s a behavioral difference. Both models reach 81.8% on TermBench, but the runtime compensates differently for each.</p><h2 id="tool-failure-limits" tabindex="-1">Tool Failure Limits <a class="header-anchor" href="#tool-failure-limits" aria-label="Permalink to &quot;Tool Failure Limits&quot;">​</a></h2><p>ForgeCode prevents infinite retry loops:</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># forge.yaml</span></span>
<span class="line"><span style="color:#89B4FA;">max_tool_failure_per_turn</span><span style="color:#94E2D5;">:</span><span style="color:#FAB387;"> 3</span><span style="color:#6C7086;font-style:italic;">  # max failures per tool before forcing completion</span></span></code></pre></div><p>When a tool fails <code>max_tool_failure_per_turn</code> times, the agent is forced to move on rather than retrying the same broken operation.</p><h2 id="tool-timeout" tabindex="-1">Tool Timeout <a class="header-anchor" href="#tool-timeout" aria-label="Permalink to &quot;Tool Timeout&quot;">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CDD6F4;">FORGE_TOOL_TIMEOUT</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">300</span><span style="color:#6C7086;font-style:italic;">  # seconds before a hanging tool is killed</span></span></code></pre></div><p>This prevents a single hung shell command from blocking the entire session.</p><h2 id="micro-evaluations" tabindex="-1">Micro-Evaluations <a class="header-anchor" href="#micro-evaluations" aria-label="Permalink to &quot;Micro-Evaluations&quot;">​</a></h2><p>ForgeCode runs per-tool reliability evaluations in CI/CD:</p><ul><li><strong>Tool-call correctness rates</strong> per tool, per model</li><li><strong><code>todo_write</code> compliance</strong> for decomposed tasks</li><li><strong>Entry-point discovery precision</strong></li><li><strong>Skill routing accuracy</strong></li></ul><p>These are not full TermBench runs — they are small, fast, targeted evals that gate releases. Each one exists because TermBench surfaced a specific failure class that needed continuous monitoring.</p><h2 id="key-takeaway" tabindex="-1">Key Takeaway <a class="header-anchor" href="#key-takeaway" aria-label="Permalink to &quot;Key Takeaway&quot;">​</a></h2><p>The tool correction layer is ForgeCode&#39;s most practically impactful innovation. It recognizes that tool-call reliability is a <strong>runtime engineering problem</strong>, not a model capabilities problem. The same model, with the same weights, produces dramatically different pass rates depending on how its tool calls are validated, corrected, and dispatched.</p>`,64)])])}const y=s(n,[["render",l]]);export{h as __pageData,y as default};
